// Extract data from VAPI end-of-call-report
const body = $input.first().json.body;
const msg = body.message;
const call = msg.call || {};
const artifact = msg.artifact || {};
const analysis = msg.analysis || {};

// Get variable values passed to VAPI (contains lead_id)
const variables = call.assistantOverrides?.variableValues || {};
const leadId = variables.lead_id || null;

// Structured outputs from VAPI
const structured = analysis.structuredData || {};

// Transcript
const transcriptArr = artifact.transcript || msg.transcript || [];
let transcriptText = '';
if (typeof transcriptArr === 'string') {
  transcriptText = transcriptArr;
} else if (Array.isArray(transcriptArr)) {
  transcriptText = transcriptArr.map(t => `${t.role}: ${t.message}`).join('\n');
}

// Call metadata
const endedReason = msg.endedReason || call.endedReason || 'unknown';
const callId = call.id || msg.callId || '';
const duration = msg.durationSeconds || call.costBreakdown?.duration || 0;

// Determine call_status
let callStatus = 'completed';
if (endedReason === 'voicemail') callStatus = 'voicemail';
else if (endedReason === 'customer-did-not-answer') callStatus = 'no_answer';
else if (endedReason === 'customer-did-not-give-microphone-permission') callStatus = 'failed';
else if (endedReason === 'assistant-error') callStatus = 'failed';

// Map structured data
const rightPersonRaw = structured.right_person || '';
const isRightPerson = ['yes', 'true', 'sí'].includes(rightPersonRaw.toLowerCase());

return [{
  json: {
    lead_id: leadId,
    call_status: callStatus,
    call_intention: structured.intention || 'unknown',
    call_budget: structured.budget || 'not_discussed',
    call_urgency: structured.urgency || 'not_discussed',
    call_motivation: structured.motivation || 'not_discussed',
    call_service_interest: structured.service_interest || 'not_discussed',
    call_right_person: isRightPerson,
    call_past_experience: structured.past_experience || 'not_discussed',
    call_summary: structured.call_summary || analysis.summary || '',
    call_transcript: transcriptText,
    vapi_call_id: callId,
    call_ended_reason: endedReason,
    call_duration_seconds: Math.round(duration),
    // For debugging
    raw_analysis: JSON.stringify(analysis),
    raw_structured: JSON.stringify(structured)
  }
}];

// No lead_id - just log the data for debugging
const data = $input.first().json;
console.log('VAPI call received without lead_id:', JSON.stringify(data));

// Still return success so VAPI doesn't retry
return [{
  json: {
    results: [{
      toolCallId: 'none',
      result: JSON.stringify({
        success: true,
        message: 'Call data received but no lead_id provided - data logged only',
        data: data
      })
    }]
  }
}];

// Handle tool-calls from VAPI (fetch lead data from Supabase)
const body = $input.first().json.body;
const msg = body.message;
const toolCalls = msg.toolCallList || msg.toolCalls || [];

// Get the first tool call
const toolCall = toolCalls[0] || {};
const functionCall = toolCall.function || {};
const args = typeof functionCall.arguments === 'string' 
  ? JSON.parse(functionCall.arguments) 
  : (functionCall.arguments || {});

return [{
  json: {
    toolCallId: toolCall.id,
    functionName: functionCall.name,
    lead_id: args.lead_id || args.leadId || null,
    lead_email: args.email || null,
    lead_phone: args.phone || null
  }
}];

// Format lead data as VAPI tool response
const input = $input.first().json;
const toolCallId = $('Parse Tool Call Args').item.json.toolCallId;

const lead = input;
const leadData = {
  id: lead.id,
  name: `${lead.first_name || ''} ${lead.last_name || ''}`.trim(),
  first_name: lead.first_name || '',
  last_name: lead.last_name || '',
  title: lead.title || '',
  company: lead.company_name || '',
  email: lead.email || '',
  phone: lead.work_direct_phone || lead.mobile_phone || lead.corporate_phone || '',
  industry: lead.industry || '',
  employees: lead.num_employees || '',
  seniority: lead.seniority || '',
  city: lead.city || '',
  state: lead.state || '',
  country: lead.country || '',
  website: lead.website || '',
  revenue: lead.annual_revenue || '',
  technologies: lead.technologies || '',
  linkedin: lead.person_linkedin_url || '',
  intent_topic: lead.primary_intent_topic || '',
  intent_score: lead.primary_intent_score || '',
  previous_calls: lead.call_attempts || 0,
  previous_status: lead.call_status || 'never_called'
};

// VAPI expects this exact response format for tool calls
return [{
  json: {
    results: [{
      toolCallId: toolCallId,
      result: JSON.stringify(leadData)
    }]
  }
}];

// Respond to assistant-request, status-update, etc.
// Just acknowledge
return [{ json: {} }];
